section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-reasoning-depth-budget-output",
  "required": [
    "task_budgets",
    "pareto_pick_budget",
    "under_thinking_pct",
    "over_thinking_pct",
    "inter_turn_compression_tokens",
    "forbidden_seen"
  ],
  "properties": {
    "task_budgets": {
      "description": "{task_id, budget_tokens, score, usd_per_call}."
    },
    "pareto_pick_budget": {
      "description": "Chosen budget tokens."
    },
    "under_thinking_pct": {
      "description": "% failures from premature stop."
    },
    "over_thinking_pct": {
      "description": "% calls in plateau zone."
    },
    "inter_turn_compression_tokens": {
      "description": "Summary cap."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
